const crypto = require('crypto');

const input = $input.first().json;
const headers = input.headers ?? {};
const body = input.body ?? {};

const headerToken = headers['x-ndeploy-token'] ?? headers['X-NDEPLOY-TOKEN'] ?? '';
// Replace this placeholder before activating the workflow.
const expectedToken = 'your-token-here';

if (!headerToken || headerToken !== expectedToken) {
  return [{ json: { statusCode: 401, body: { error: 'invalid_token', code: 'UNAUTHORIZED' } } }];
}

if (!body || !Array.isArray(body.credentials)) {
  return [{ json: { statusCode: 400, body: { error: 'credentials_must_be_an_array', code: 'BAD_REQUEST' } } }];
}

const credentials = body.credentials.map((item, index) => {
  if (!item || typeof item !== 'object' || Array.isArray(item)) {
    return { invalid: true, index };
  }

  const requestId = item.source_id ?? item.id;
  if (requestId === undefined || requestId === null || requestId === '') {
    return { invalid: true, index };
  }

  return {
    source_id: String(requestId),
    id: item.id != null ? String(item.id) : String(requestId),
    name: item.name != null ? String(item.name) : null,
    type: item.type != null ? String(item.type) : null,
    invalid: false
  };
});

const invalidItem = credentials.find((item) => item.invalid);
if (invalidItem) {
  return [{ json: { statusCode: 400, body: { error: `credential_at_index_${invalidItem.index}_must_include_source_id_or_id`, code: 'BAD_REQUEST' } } }];
}

return [{
  json: {
    statusCode: 200,
    tmpFile: `/tmp/ndeploy-credential-export-${crypto.randomUUID()}.json`,
    credentials
  }
}];

const request = $('Validate Request').first().json;
const execResult = $input.first().json ?? {};
const stdout = String(execResult.stdout ?? execResult.data ?? '').trim();

try {
  if (!stdout) {
    return [{ json: { statusCode: 500, body: { error: 'empty_export_response', code: 'INTERNAL_ERROR' } } }];
  }

  const parsed = JSON.parse(stdout);

  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed) && parsed.error) {
    return [{ json: { statusCode: 500, body: parsed } }];
  }

  const exportedItems = Array.isArray(parsed)
    ? parsed
    : Array.isArray(parsed.credentials)
      ? parsed.credentials
      : Array.isArray(parsed.data)
        ? parsed.data
        : [];

  const byId = new Map();
  const byNameType = new Map();

  for (const item of exportedItems) {
    if (!item || typeof item !== 'object' || Array.isArray(item)) continue;

    const candidateId = item.source_id ?? item.id;
    if (candidateId !== undefined && candidateId !== null && candidateId !== '') {
      byId.set(String(candidateId), item);
    }

    if (item.name && item.type) {
      byNameType.set(`${String(item.name)}::${String(item.type)}`, item);
    }
  }

  const credentials = request.credentials.map((requested) => {
    const directMatch = byId.get(requested.source_id) || byId.get(requested.id);
    const fallbackMatch = requested.name && requested.type
      ? byNameType.get(`${requested.name}::${requested.type}`)
      : null;
    const resolved = directMatch || fallbackMatch || null;
    const data = resolved && resolved.data && typeof resolved.data === 'object' && !Array.isArray(resolved.data)
      ? resolved.data
      : null;

    return {
      source_id: requested.source_id,
      data
    };
  });

  return [{ json: { statusCode: 200, body: { credentials } } }];
} catch {
  return [{ json: { statusCode: 500, body: { error: 'invalid_export_response', code: 'INTERNAL_ERROR', details: { preview: stdout.slice(0, 500) } } } }];
}
